window.addEventListener('load',()=>{try{const p={...window.DAILY_20260714_CORE,...window.DAILY_20260714_ANALYSIS};if(!p.patchId)throw new Error('daily data missing');if(!S.patchHistory.some(x=>x.patchId===p.patchId)){applyDailyPatchV3(p);const log=S.dailyLogs.find(x=>x.patchId===p.patchId);if(log){log.roadmapIntervention=p.roadmapIntervention;log.missingInformation=p.missingInformation;log.weeklyObservations=p.weeklyObservations;log.candidateConfidenceNote='Daily Diagnosis confidence is provisional; formal Career Model Confidence remains unchanged until Weekly Review.'}save();renderAll()}}catch(e){console.error('July 14 daily seed failed',e)}},{once:true});